workflow-item.script:
if (inputProperties.get("eventType") != 'CREATE_DEPLOYMENT')
    throw '';


var vaaEvents = {
  "compute.removal.pre":	"Compute Removal pre",
  "compute.removal.post":	"Compute Removal post",
  "compute.provision.pre":	"Compute Provision pre",
  "compute.provision.post":	"Compute Provision post",
  "deployment.request.pre": "Deployment Request Pre",
  "deployment.resource.request.pre": "deployment.resource.request.pre",
  "deployment.resource.request.post": "deployment.resource.request.post",
  "deployment.request.post": "deployment.request.post",

}


//Find out VAA event
var vaaEvent = System.getContext().getParameter("__metadata_eventTopicId");
System.log("VAA event name:	" + vaaEvents[vaaEvent]);
System.log("VAA event name (dotted) :	" + vaaEvent);


var customProperties = new Properties();
customProperties = inputProperties.get("requestInputs");

var deploymentName = inputProperties.get("deploymentName");
var vmName = "raaj-" + deploymentName.toLowerCase();
System.log("vmName	:" + vmName);

if (customProperties != null) {
  environment = customProperties.get("environment");
  application = customProperties.get("application");
  owner = customProperties.get("owner");

  System.log("environment	:" + environment);
  System.log("application	:" + application);
  System.log("owner :" + owner);
}
